1	import React from "react";
2	import { Box, Text } from "ink";
3	import { useStore } from "../store/index.js";
4	import type { StatusBarData, StatusBarField } from "../../shared/types.js";
5	import { config } from "../../shared/config.js";
6	
7	function formatDuration(seconds: number): string {
8	  if (seconds < 60) return `${seconds}s`;
9	  const m = Math.floor(seconds / 60);
10	  const s = seconds % 60;
11	  return s > 0 ? `${m}m${s}s` : `${m}m`;
12	}
13	
14	function formatCost(cost: number): string {
15	  return `$${cost.toFixed(2)}`;
16	}
17	
18	function formatTokens(n: number): string {
19	  if (n >= 1000000) return `${(n / 1000000).toFixed(1)}M`;
20	  if (n >= 1000) return `${(n / 1000).toFixed(1)}k`;
21	  return `${n}`;
22	}
23	
24	function renderField(
25	  key: string,
26	  _label: string,
27	  data: StatusBarData
28	): React.ReactElement | null {
29	  switch (key) {
30	    case "model":
31	      return data.model ? <Text color="green">{data.model}</Text> : null;
32	    case "totalTokens":
33	      return <Text color="yellow">Total: {formatTokens(data.totalTokens)}</Text>;
34	    case "contextTokens":
35	      return <Text color="yellow">Ctx: {formatTokens(data.contextTokens)}</Text>;
36	    case "contextPercent": {
37	      const pct = data.contextPercent;
38	      const color = pct > 80 ? "red" : pct > 50 ? "yellow" : "green";
39	      return <Text color={color}>Ctx: {pct.toFixed(1)}%</Text>;
40	    }
41	    case "cost":
42	      return <Text color="cyan">{formatCost(data.cost)}</Text>;
43	    case "durationSeconds":
44	      return <Text color="magenta">{formatDuration(data.durationSeconds)}</Text>;
45	    case "gitBranch":
46	      return data.gitBranch ? (
47	        <Text color="yellow">@ {data.gitBranch}</Text>
48	      ) : (
49	        <Text color="gray">@ no git</Text>
50	      );
51	    case "gitDiffStats":
52	      if (!data.gitDiffStats) return null;
53	      return (
54	        <Text>
55	          <Text color="green">+{data.gitDiffStats.added}</Text>
56	          <Text> </Text>
57	          <Text color="red">-{data.gitDiffStats.removed}</Text>
58	          <Text> </Text>
59	          <Text color="yellow">~{data.gitDiffStats.modified}</Text>
60	        </Text>
61	      );
62	    case "style":
63	      return data.style ? <Text color="white">Style: {data.style}</Text> : null;
64	    case "sessionId":
65	      return data.sessionId ? <Text color="gray">{data.sessionId.slice(0, 8)}</Text> : null;
66	    default:
67	      return null;
68	  }
69	}
70	
71	interface StatusBarProps {
72	  fields?: StatusBarField[];
73	}
74	
75	const EMPTY_EVENTS: never[] = [];
76	
77	export function StatusBar({ fields }: StatusBarProps): React.ReactElement {
78	  const activeTabId = useStore((s) => s.activeTabId);
79	  const allStatus = useStore((s) => s.tabStatus);
80	  const allCompactEvents = useStore((s) => s.tabCompactEvents);
81	
82	  const data = activeTabId ? allStatus[activeTabId] : null;
83	  const compactEvents = (activeTabId && allCompactEvents[activeTabId]) || EMPTY_EVENTS;
84	
85	  const enabledFields = (fields || config.defaultStatusBarFields).filter(
86	    (f) => f.enabled
87	  );
88	
89	  if (!data) {
90	    return (
91	      <Box paddingX={1}>
92	        <Text color="gray">No active session</Text>
93	      </Box>
94	    );
95	  }
96	
97	  const lastCompact = compactEvents[compactEvents.length - 1];
98	
99	  return (
100	    <Box paddingX={1} flexDirection="row" gap={1}>
101	      {enabledFields.map((field) => {
102	        const rendered = renderField(field.key, field.label, data);
103	        if (!rendered) return null;
104	        return (
105	          <React.Fragment key={field.key}>
106	            {rendered}
107	            <Text color="gray"> | </Text>
108	          </React.Fragment>
109	        );
110	      })}
111	      {lastCompact && <Text color="red">* compacted</Text>}
112	    </Box>
113	  );
114	}
