1	import React, { useState } from "react";
2	import { Box, Text, useInput } from "ink";
3	import TextInput from "ink-text-input";
4	import { useStore } from "../store/index.js";
5	import type { Session } from "../../shared/types.js";
6	
7	interface SessionSidebarProps {
8	  onOpenSession: (session: Session) => void;
9	  visible: boolean;
10	}
11	
12	const COLORS = ["red", "green", "yellow", "blue", "magenta", "cyan", "white"];
13	
14	function formatDate(ts: number): string {
15	  const d = new Date(ts);
16	  const month = (d.getMonth() + 1).toString().padStart(2, "0");
17	  const day = d.getDate().toString().padStart(2, "0");
18	  return `${month}/${day}`;
19	}
20	
21	function formatCost(cost: number): string {
22	  if (cost === 0) return "";
23	  return `$${cost.toFixed(2)}`;
24	}
25	
26	export function SessionSidebar({
27	  onOpenSession,
28	  visible,
29	}: SessionSidebarProps): React.ReactElement {
30	  const sessions = useStore((s) => s.sessions);
31	  const sessionFilter = useStore((s) => s.sessionFilter);
32	  const setSessionFilter = useStore((s) => s.setSessionFilter);
33	  const updateSessionColor = useStore((s) => s.updateSessionColor);
34	  const updateSessionName = useStore((s) => s.updateSessionName);
35	
36	  const [selectedIdx, setSelectedIdx] = useState(0);
37	  const [renaming, setRenaming] = useState<string | null>(null);
38	  const [renameValue, setRenameValue] = useState("");
39	
40	  const filtered = sessionFilter
41	    ? sessions.filter((s) => s.name.toLowerCase().includes(sessionFilter.toLowerCase()))
42	    : sessions;
43	
44	  useInput(
45	    (input, key) => {
46	      if (!visible) return;
47	
48	      if (key.upArrow) {
49	        setSelectedIdx((i) => Math.max(0, i - 1));
50	        return;
51	      }
52	      if (key.downArrow) {
53	        setSelectedIdx((i) => Math.min(filtered.length - 1, i + 1));
54	        return;
55	      }
56	      if (key.return && filtered[selectedIdx]) {
57	        if (renaming) return;
58	        onOpenSession(filtered[selectedIdx]);
59	        return;
60	      }
61	      if (input === "r" && !renaming && filtered[selectedIdx]) {
62	        setRenaming(filtered[selectedIdx].id);
63	        setRenameValue(filtered[selectedIdx].name);
64	        return;
65	      }
66	      if (input === "c" && filtered[selectedIdx]) {
67	        const session = filtered[selectedIdx];
68	        const currentIdx = COLORS.indexOf(session.color || "");
69	        const nextColor = COLORS[(currentIdx + 1) % COLORS.length];
70	        updateSessionColor(session.id, nextColor);
71	        return;
72	      }
73	    },
74	    { isActive: visible }
75	  );
76	
77	  function handleRenameSubmit(value: string): void {
78	    if (renaming && value.trim()) {
79	      updateSessionName(renaming, value.trim());
80	    }
81	    setRenaming(null);
82	    setRenameValue("");
83	  }
84	
85	  if (!visible) return <></>;
86	
87	  return (
88	    <Box flexDirection="column" padding={1}>
89	      <Text bold color="cyan">Sessions</Text>
90	
91	      <Box marginY={1}>
92	        <Text color="gray">/ </Text>
93	        <TextInput
94	          value={sessionFilter}
95	          onChange={setSessionFilter}
96	          placeholder="Filter..."
97	          focus={visible && !renaming}
98	        />
99	      </Box>
100	
101	      {filtered.map((session, idx) => {
102	        const isSelected = idx === selectedIdx;
103	        const isRenaming = renaming === session.id;
104	
105	        return (
106	          <Box key={session.id} flexDirection="row">
107	            <Text color={session.color || "white"}>
108	              {isSelected ? "> " : "  "}o{" "}
109	            </Text>
110	            {isRenaming ? (
111	              <TextInput
112	                value={renameValue}
113	                onChange={setRenameValue}
114	                onSubmit={handleRenameSubmit}
115	                focus={true}
116	              />
117	            ) : (
118	              <Text
119	                color={isSelected ? "white" : "gray"}
120	                bold={isSelected}
121	              >
122	                {session.name}
123	              </Text>
124	            )}
125	            <Text color="gray">
126	              {" "}
127	              {formatDate(session.updatedAt)}
128	              {formatCost(session.totalCost) && ` ${formatCost(session.totalCost)}`}
129	            </Text>
130	          </Box>
131	        );
132	      })}
133	
134	      {filtered.length === 0 && (
135	        <Text color="gray">No sessions found</Text>
136	      )}
137	
138	      <Box marginTop={1}>
139	        <Text color="gray" dimColor>
140	          up/dn nav | Enter open | r rename | c color
141	        </Text>
142	      </Box>
143	    </Box>
144	  );
145	}
