1	import React, { useEffect, useRef, useState } from "react";
2	import { Box, useInput } from "ink";
3	import { Layout } from "./shell/components/Layout.js";
4	import { TabBar } from "./shell/components/TabBar.js";
5	import { ChatView } from "./shell/components/ChatView.js";
6	import { InputBar } from "./shell/components/InputBar.js";
7	import { StatusBar } from "./shell/components/StatusBar.js";
8	import { ContextBar } from "./shell/components/ContextBar.js";
9	import { SessionSidebar } from "./shell/components/SessionSidebar.js";
10	import { SkillsSidebar } from "./shell/components/SkillsSidebar.js";
11	import { useStore } from "./shell/store/index.js";
12	import { useWorkerManager } from "./shell/hooks/useWorkerManager.js";
13	import { useSessions } from "./shell/hooks/useSessions.js";
14	import { useSkillDiscovery } from "./shell/hooks/useSkillDiscovery.js";
15	import { useGit } from "./shell/hooks/useGit.js";
16	import type { CliArgs } from "./cli/index.js";
17	
18	import type { Pin } from "./shared/types.js";
19	
20	const EMPTY_PINS: Pin[] = [];
21	
22	interface AppProps {
23	  args: CliArgs;
24	}
25	
26	export function App({ args }: AppProps): React.ReactElement {
27	  const createTab = useStore((s) => s.createTab);
28	  const activeTabId = useStore((s) => s.activeTabId);
29	  const tabs = useStore((s) => s.tabs);
30	  const addPin = useStore((s) => s.addPin);
31	  const removePin = useStore((s) => s.removePin);
32	  const clearOneShots = useStore((s) => s.clearOneShots);
33	  const statusBarFields = useStore((s) => s.statusBarFields);
34	  const allPins = useStore((s) => s.pins);
35	  const activePins = (activeTabId && allPins[activeTabId]) || EMPTY_PINS;
36	
37	  const [initialized, setInitialized] = useState(false);
38	  const spawnedTabsRef = useRef<Set<string>>(new Set());
39	  const [sidebarVisible, setSidebarVisible] = useState({
40	    sessions: true,
41	    skills: true,
42	  });
43	
44	  const { spawnWorker, sendPrompt, killWorker, sendToWorker } = useWorkerManager(args.cwd);
45	  useSessions();
46	  useSkillDiscovery(args.cwd);
47	  useGit(args.cwd);
48	
49	  // Create initial tab and spawn its worker
50	  useEffect(() => {
51	    if (!initialized) {
52	      const tab = createTab("New Session");
53	      spawnedTabsRef.current.add(tab.id);
54	      spawnWorker(tab.id);
55	      setInitialized(true);
56	    }
57	  }, [initialized, createTab, spawnWorker]);
58	
59	  // Spawn worker when new tab is created (only once per tab)
60	  useEffect(() => {
61	    for (const tab of tabs) {
62	      if (!spawnedTabsRef.current.has(tab.id)) {
63	        spawnedTabsRef.current.add(tab.id);
64	        spawnWorker(tab.id);
65	      }
66	    }
67	  }, [tabs, spawnWorker]);
68	
69	  // Sidebar toggle hotkeys
70	  useInput((input, key) => {
71	    if (input === "h" && key.ctrl) {
72	      setSidebarVisible((v) => ({ ...v, sessions: !v.sessions }));
73	    }
74	    if (input === "s" && key.ctrl) {
75	      setSidebarVisible((v) => ({ ...v, skills: !v.skills }));
76	    }
77	    // Ctrl+R — context reset
78	    if (input === "r" && key.ctrl && activeTabId) {
79	      sendToWorker(activeTabId, { type: "context_reset" });
80	    }
81	    // Ctrl+Shift+S — snapshot
82	    if (input === "S" && key.ctrl && activeTabId) {
83	      sendToWorker(activeTabId, { type: "context_snapshot" });
84	    }
85	  });
86	
87	  function handleSubmit(text: string): void {
88	    if (!activeTabId) return;
89	
90	    // Extract @file references
91	    const fileMatches = text.match(/@(\S+)/g) || [];
92	    for (const match of fileMatches) {
93	      addPin(activeTabId, "file", match.slice(1), "prompt");
94	    }
95	
96	    // Extract /skill references
97	    const skillMatches = text.match(/\/(\S+)/g) || [];
98	    for (const match of skillMatches) {
99	      addPin(activeTabId, "skill", match.slice(1), "prompt");
100	    }
101	
102	    // Clean prompt text
103	    const cleanText = text
104	      .replace(/@\S+/g, "")
105	      .replace(/\/\S+/g, "")
106	      .trim();
107	
108	    if (cleanText) {
109	      const currentPins = useStore.getState().getPins(activeTabId);
110	      sendPrompt(activeTabId, cleanText, currentPins);
111	      clearOneShots(activeTabId);
112	    }
113	  }
114	
115	  return (
116	    <Layout
117	      sessionSidebar={
118	        <SessionSidebar
119	          onOpenSession={(session) => {
120	            const tab = createTab(session.name);
121	            spawnWorker(tab.id);
122	          }}
123	          visible={sidebarVisible.sessions}
124	        />
125	      }
126	      center={
127	        <Box flexDirection="column" flexGrow={1}>
128	          <TabBar />
129	          <ChatView />
130	          <ContextBar
131	            pins={activePins}
132	            onRemovePin={(pinId) => {
133	              if (activeTabId) removePin(activeTabId, pinId);
134	            }}
135	          />
136	          <InputBar onSubmit={handleSubmit} />
137	          <StatusBar fields={statusBarFields} />
138	        </Box>
139	      }
140	      skillsSidebar={
141	        <SkillsSidebar
142	          visible={sidebarVisible.skills}
143	          onPinSkill={(skill, mode) => {
144	            if (activeTabId) {
145	              addPin(activeTabId, "skill", skill.name, mode);
146	            }
147	          }}
148	        />
149	      }
150	    />
151	  );
152	}
