1	import React from "react";
2	import { Box, Text, useInput } from "ink";
3	import { useStore } from "../store/index.js";
4	
5	export function TabBar(): React.ReactElement {
6	  const tabs = useStore((s) => s.tabs);
7	  const activeTabId = useStore((s) => s.activeTabId);
8	  const setActiveTab = useStore((s) => s.setActiveTab);
9	  const createTab = useStore((s) => s.createTab);
10	  const closeTab = useStore((s) => s.closeTab);
11	
12	  useInput((input, key) => {
13	    if (input === "t" && key.ctrl) {
14	      createTab();
15	      return;
16	    }
17	
18	    if (input === "w" && key.ctrl && activeTabId) {
19	      closeTab(activeTabId);
20	      return;
21	    }
22	
23	    if (key.ctrl && input >= "1" && input <= "9") {
24	      const idx = parseInt(input, 10) - 1;
25	      if (tabs[idx]) {
26	        setActiveTab(tabs[idx].id);
27	      }
28	      return;
